import Navbar from "./Navbar";
import Title from './Title'
import theme from '../theme'
import { useState } from 'react'

const Layout = ({ children }) => {

  const [dimensions, setDimensions] = useState({width:0, height:0})

  useEffect(()=>{
    setDimensions({
      width: window.innerWidth,
      height: window.innerHeight
    })
  },[])

  return (
    <>
      <style>{style}</style>
      <iframe width={window.innerWidth} height={window.innerHeight} src="https://editor.p5js.org/jithunni.ks/embed/yOW6xJTZ1"></iframe>
      <div className='wrapper'>
        <Title />
        <Navbar />
        {children}
      </div>
    </>
  )
};

const style = `
  * {
    font-family:Roboto;
  }
  ol {
      padding-left:1rem;
  }
  .wrapper {
    width:70vw;
    margin:auto;
    min-width:600px;
  }
  body {
    background-color:${theme.darkBackground};
  }
  iframe {
    margin:0;
    padding:0;
    border:none;
  }
`;

export default Layout;
